var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"수, 숨 넘어가겠네......","JPN":"も、もう無理……","ENG":"I-I can barely breathe...","TWN":"喘、喘死我了……"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"잠깐 쉬죠. 여기라면 쉽게 쫓아오지 못할 거예요.","JPN":"少し休みましょう。ここなら簡単には追って来れないはずです。","ENG":"Let's take a break. They can't follow us this far away so quickly.","TWN":"我們歇一下吧，她們應該不能馬上追上來。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"메이드가 대체 총질을 왜 저렇게 잘해?! 뭔가 이상하잖아?!","JPN":"メイドなのになんで銃の扱いが上手いわけ！？　おかしすぎるでしょ！？","ENG":"How come those maids are so good at shooting? Does that make sense to you?","TWN":"女僕什麼時候會射擊了？！妳不覺得很奇怪嗎？！"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그러려니 하세요. 저희 사장님은 로봇인데요, 뭘.","JPN":"あり得るんじゃないですか？　私たちの社長なんかロボットですからね。","ENG":"It doesn't, but then again, our boss is a robot.","TWN":"算了，我們老闆還是機器人呢。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"일단 상황 설명을 해 주세요. 어떻게 된 일이죠?","JPN":"ひとまず状況を説明してください。どういうことですか？","ENG":"Please explain the situation. What happened?","TWN":"這到底是什麼情況？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"처음에는 머릿수에서 밀려도 엄폐물을 활용해서 제법 잘 버티고 있었어.","JPN":"最初は数的不利でも遮蔽物なり活用して、なんとか耐えられたんだけど……","ENG":"At first, we did a good job stalling the victims by using the structures around us to make up for our inferior numbers.","TWN":"剛開始雖然我們人少，但利用掩蔽物撐了下去。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"하지만 중간부터 사장님이 방어도 하지 않고 적극적으로 공격해 오더라고.","JPN":"途中から社長が防御もせずに、一方的に攻撃を仕掛けてきたのよ。","ENG":"But halfway through the fight, the Boss started attacking aggressively without bothering to defend himself.","TWN":"但是突然，老闆不再防禦，反而積極進攻。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"메이드 아가씨들은 차마 주인님을 공격할 수가 없어서 결국......","JPN":"メイドのお嬢ちゃんたちは、ご主人様を攻撃することができずに結局……","ENG":"The maid ladies couldn't bring themselves to attack their master, so...","TWN":"女僕小姐們又不敢攻擊自己的主人，所以就……"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"말도 안 돼!","JPN":"あり得ない！","ENG":"This is ridiculous!","TWN":"怎麼會！"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"이 주시윤이란 녀석이 범인 아니었어?","JPN":"このアキヤマ・シリュウってやつが、犯人じゃなかったの？","ENG":"I thought this guy, Shiyoon, was the perpetrator.","TWN":"難道兇手不是周時雲嗎？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"범인을 잡았는데 희생자가 더 생길 리 없잖아?!","JPN":"犯人を捕まえたのに、犠牲者が増えるはずないじゃない！","ENG":"And there shouldn't have been more victims now that he's with us.","TWN":"我們都抓到兇手了，怎麼還會有人中招。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"혹은 선배가 범인이 아니었다거나 말이죠.","JPN":"もしくは先輩が犯人じゃなかったってことですね。","ENG":"Or, maybe he's not the perpetrator.","TWN":"也許前輩並不是兇手。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"뭐......?","JPN":"えっ……？","ENG":"What?","TWN":"什麼……？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"잠시만요. 확인해 봐야겠어요.","JPN":"ちょっと待ってください。確認した方が良さそうです。","ENG":"Give me a moment. Let me check something.","TWN":"稍等，我需要確認一下。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......역시, 예상대로네요.","JPN":"……やっぱり、予想通りですね。","ENG":"It's just as I thought.","TWN":"……果然不出所料。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"자, 선배의 이마를 보세요.","JPN":"ほら、先輩の額を見てください。","ENG":"Here, take a look at his forehead.","TWN":"妳們看前輩的額頭。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};